}

let texto = `📋 Pedidos do usuário ${targetUserId}:\n`;
texto += `👤 Nome: ${usuario.nomeCliente || 'N/A'}\n\n`;
pedidos.forEach((p, i) => {
  const itens = p['Pratos (selecione ao menos 1)'];
  const itensStr = Array.isArray(itens) ? itens.join(', ') : itens;
  const entrada = Array.isArray(p['Entrada']) ? p['Entrada'].join(', ') : (p['Entrada'] || '');
  const status = p.status || p.statusPedidoAtendente || 'sem status';
  const criadoEm = p.criadoEm ? new Date(p.criadoEm).toLocaleString('pt-BR') : 'N/A';
  texto += `🔢 Pedido #${i}:\n`;
  texto += `   Pratos: ${itensStr}\n`;
  if (entrada) texto += `   Entradas: ${entrada}\n`;
  texto += `   Status: ${status}\n`;
  texto += `   Criado: ${criadoEm}\n`;
  if (p.observacoes) texto += `   Obs: ${p.observacoes}\n`;
  texto += '\n';
});

return [{ json: { sucesso: true, senderId, msg: texto } }];

// /pedido_atualizar <userId> <numero_pedido> <status>
// Status: preparando | em_entrega | entregue
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 3) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /pedido_atualizar <telegramId> <numeroPedido> <status>\n\nStatus válidos: preparando | em_entrega | entregue\n\nExemplo: /pedido_atualizar 123456789 0 em_entrega' } }];
}

const targetUserId = String(args[0]);
const numPedido = parseInt(args[1]);
const novoStatus = args[2].toLowerCase();
const statusValidos = ['preparando', 'em_entrega', 'entregue'];

if (!statusValidos.includes(novoStatus)) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Status inválido: "${novoStatus}"\nStatus válidos: ${statusValidos.join(' | ')}` } }];
}

const usuario = db.usuario?.[targetUserId];
if (!usuario) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Usuário ${targetUserId} não encontrado.` } }];
}

const pedido = usuario.pedidos?.[numPedido];
if (!pedido) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Pedido #${numPedido} não encontrado para o usuário ${targetUserId}.` } }];
}

// Atualiza status SEM apagar o pedido
pedido.status = novoStatus;
pedido.statusPedidoAtendente = novoStatus;
pedido.atualizadoEm = new Date().toISOString();
pedido.atualizadoPor = senderId;

const emoji = { preparando: '🔥', em_entrega: '🚚', entregue: '✅' }[novoStatus] || '📋';
return [{ json: { sucesso: true, senderId, targetUserId, numPedido, novoStatus, msg: `${emoji} Pedido #${numPedido} do usuário ${targetUserId} atualizado para: <b>${novoStatus}</b>` } }];

// /pedido_cancelar <userId> <numeroPedido>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 2) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /pedido_cancelar <telegramId> <numeroPedido>\nExemplo: /pedido_cancelar 123456789 0' } }];
}

const targetUserId = String(args[0]);
const numPedido = parseInt(args[1]);
const usuario = db.usuario?.[targetUserId];

if (!usuario?.pedidos?.[numPedido]) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Pedido #${numPedido} não encontrado para o usuário ${targetUserId}.` } }];
}

usuario.pedidos[numPedido].status = 'cancelado';
usuario.pedidos[numPedido].statusPedidoAtendente = 'cancelado';
usuario.pedidos[numPedido].canceladoEm = new Date().toISOString();
usuario.pedidos[numPedido].canceladoPor = senderId;

return [{ json: { sucesso: true, senderId, msg: `🚫 Pedido #${numPedido} do usuário ${targetUserId} marcado como <b>cancelado</b>.` } }];

// /mesa_consultar <userId>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 1) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /mesa_consultar <telegramId>' } }];
}

const targetUserId = String(args[0]);
const mesas = db.mesas || [];
const reservasDoUsuario = [];

mesas.forEach(mesa => {
  mesa.reservas.forEach(reserva => {
    if (String(reserva.userId) === targetUserId) {
      reservasDoUsuario.push({ mesaId: mesa.id, tipo: mesa.tipo, capacidade: mesa.capacidade, ...reserva });
    }
  });
});

if (reservasDoUsuario.length === 0) {
  return [{ json: { sucesso: true, senderId, msg: `📋 Usuário ${targetUserId} não possui reservas de mesa.` } }];
}

let texto = `🍽️ Reservas do usuário ${targetUserId}:\n\n`;
reservasDoUsuario.forEach((r, i) => {
  texto += `📌 Reserva ${i + 1}:\n`;
  texto += `   Mesa #${r.mesaId} — ${r.tipo} (${r.capacidade} lugares)\n`;
  texto += `   📅 Data: ${r.data}\n`;
  texto += `   🕐 Hora: ${r.hora}\n`;
  texto += `   👥 Pessoas: ${r.pessoas}\n\n`;
});

return [{ json: { sucesso: true, senderId, msg: texto } }];

// /mesa_disponiveis [data] [hora]
// Sem args: lista todas as mesas com status geral
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (!db.mesas) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Sistema de mesas ainda não inicializado. Aguarde algum usuário acessar o fluxo de reservas.' } }];
}

const data = args[0] || null;
const hora = args[1] || null;

let texto = '🍽️ Mesas disponíveis:\n\n';
db.mesas.forEach(mesa => {
  const ocupada = data && hora ? mesa.reservas.some(r => r.data === data && r.hora === hora) : false;
  const qtdReservas = mesa.reservas.length;
  const status = data && hora ? (ocupada ? '🔴 Ocupada' : '🟢 Livre') : `📅 ${qtdReservas} reserva(s)`;
  texto += `Mesa #${mesa.id} — ${mesa.tipo} (${mesa.capacidade} lugares) — ${status}\n`;
});

if (data && hora) {
  texto = `🍽️ Disponibilidade para ${data} às ${hora}:\n\n` + texto.replace('Mesas disponíveis:\n\n', '');
}

return [{ json: { sucesso: true, senderId, msg: texto } }];

// /mesa_reservar <userId> <mesaId> <data YYYY-MM-DD> <hora HH:MM> <pessoas>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 5) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /mesa_reservar <telegramId> <mesaId> <data> <hora> <pessoas>\nExemplo: /mesa_reservar 123456789 3 2025-12-25 19:00 4' } }];
}

const [targetUserId, mesaIdStr, data, hora, pessoasStr] = args;
const mesaId = parseInt(mesaIdStr);
const pessoas = parseInt(pessoasStr);

if (!db.mesas) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Sistema de mesas não inicializado.' } }];
}

const mesa = db.mesas.find(m => m.id === mesaId);
if (!mesa) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} não encontrada.` } }];
}

const conflito = mesa.reservas.some(r => r.data === data && r.hora === hora);
if (conflito) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} já está reservada em ${data} às ${hora}.` } }];
}

mesa.reservas.push({ data, hora, pessoas, userId: targetUserId, criadoEm: new Date().toISOString(), criadoPorAtendente: senderId });

return [{ json: { sucesso: true, senderId, msg: `✅ Mesa #${mesaId} reservada!\n\n👤 Usuário: ${targetUserId}\n🍽️ Mesa: #${mesaId} — ${mesa.tipo} (${mesa.capacidade} lugares)\n📅 Data: ${data}\n🕐 Hora: ${hora}\n👥 Pessoas: ${pessoas}` } }];

// /mesa_cancelar <userId> <mesaId> <data> <hora>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 4) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /mesa_cancelar <telegramId> <mesaId> <data> <hora>\nExemplo: /mesa_cancelar 123456789 3 2025-12-25 19:00' } }];
}

const [targetUserId, mesaIdStr, data, hora] = args;
const mesaId = parseInt(mesaIdStr);

if (!db.mesas) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Sistema de mesas não inicializado.' } }];
}

const mesa = db.mesas.find(m => m.id === mesaId);
if (!mesa) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Mesa #${mesaId} não encontrada.` } }];
}

const idx = mesa.reservas.findIndex(r => String(r.userId) === String(targetUserId) && r.data === data && r.hora === hora);
if (idx === -1) {
  return [{ json: { sucesso: false, senderId, msg: `❌ Reserva não encontrada para o usuário ${targetUserId} na mesa #${mesaId} em ${data} às ${hora}.` } }];
}

mesa.reservas.splice(idx, 1);
return [{ json: { sucesso: true, senderId, msg: `🗑️ Reserva cancelada com sucesso!\n\n👤 Usuário: ${targetUserId}\n🍽️ Mesa: #${mesaId}\n📅 Data: ${data}\n🕐 Hora: ${hora}` } }];

