const novoEndereco = args.slice(1).join(' ').trim();

if (!novoEndereco) {
  return [{ json: { sucesso: false, senderId, msg: '❌ O endereço não pode estar vazio.' } }];
}

if (!db.usuario) db.usuario = {};
if (!db.usuario[targetUserId]) {
  db.usuario[targetUserId] = {
    endereco: '', numeroPedidos: 0, pedidos: [],
    pagamento: 'nenhum', nomeCliente: 'nenhum', emailCliente: ''
  };
}

const enderecoAnterior = db.usuario[targetUserId].endereco || '(vazio)';
db.usuario[targetUserId].endereco = novoEndereco;

return [{ json: {
  sucesso: true, senderId, targetUserId,
  msg: `✅ <b>Endereço atualizado!</b>\n\n👤 Usuário: <code>${targetUserId}</code>\n\n📍 Anterior: ${enderecoAnterior}\n📍 Novo: ${novoEndereco}`
} }];

// /endereco_consultar <userId>
const db = $getWorkflowStaticData('global');
const args = $json.args;
const senderId = $json.senderId;

if (args.length < 1) {
  return [{ json: { sucesso: false, senderId, msg: '❌ Uso: /endereco_consultar <telegramId>' } }];
}

const targetUserId = String(args[0]);
const usuario = db.usuario?.[targetUserId];

if (!usuario) {
  return [{ json: { sucesso: false, senderId,
    msg: `❌ Usuário <code>${targetUserId}</code> não encontrado no sistema.` } }];
}

const endereco = usuario.endereco || '(não preenchido)';
const nome     = usuario.nomeCliente || '(não informado)';
const emailCliente = usuario.emailCliente;

return [{ json: {
  sucesso: true, senderId,
  msg: `📍 <b>Endereço do usuário</b>\n\n👤 Usuário: <code>${targetUserId}</code>\n🧑 Nome: ${nome}\n✉️ Email: ${emailCliente}\n📍 Endereço: ${endereco}`
} }];
